"""
MKT Context Commentary — Psalms chapters 140–146
Run: python3 scripts/zc-context-psalms-140-146.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)

Key decisions in this range:
- Ps 140: "Davidic" designation despite being in the final Psalms cluster; serpent-tongue
  imagery echoes Gen 3 as well as ANE wisdom; burning-coals imprecation (v10)
- Ps 141: prayer-as-incense links individual petition to temple tamid offering (v2);
  righteous-rebuke-as-oil is a wisdom tradition hospitality honor image (v5)
- Ps 142: superscription ties to cave episodes (1 Sam 22:1/24:3); pour-out idiom
  (šipok śîḥî) shared with Hannah (1 Sam 1:15) and Lam 2:19
- Ps 143: one of the seven penitential psalms; v2 quoted by Paul in Gal 2:16/Rom 3:20;
  'good Spirit' (v10) is one of only three OT occurrences
- Ps 144: borrows Ps 8:4 (vv3-4) for the royal humility move; vv5-6 theophany = Sinai
  language; yĕmîn šāqer (false right hand) inverts the covenant-oath gesture
- Ps 145: the only psalm titled 'Tĕhillāh' (Praise) — from which the book's Hebrew name
  'Tĕhillîm' comes; the missing nun-verse is present in 11QPsᵃ and LXX;
  vv15-16 used liturgically as grace before meals in Jewish practice
- Ps 146: opens the Hallel finale (Pss 146-150, all beginning/ending Hallelujah);
  v3 anti-patronage principle (ANE patron-client system); vv5-9 divine-action catalogue
  quoted by Jesus as evidence of the messianic era (Matt 11:4-5 / Luke 7:22)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "140": {
    "1": '<p>Psalm 140 bears the superscription "For the director of music, a Psalm of David" — placing it among the final Davidic psalms in the Psalter (Pss 138–145 form a cluster, after the long Asaphite, Korahite, and Hallel collections). The request "rescue me from evil men; protect me from violent men (<em>ʾîš ḥămāsîm</em>)" invokes the classic Psalter opposition between the righteous speaker and the violent aggressors. <em>Ḥāmās</em> (violence, injustice, wrong) is a legal term for the wrongful violence that destroys social order — it appears in the flood narrative (Gen 6:11, 13) as the definitive reason for God\'s judgment on the pre-flood world.</p>',
    "2": '<p>"Who scheme wickedness in their hearts and stir up conflict every day" — <em>yāgûrû mĕlḥāmôt</em> (they stir up/gather wars). The movement from heart-scheming to daily conflict-rousing is the two-stage description of the wicked in the Psalter\'s moral anthropology: wickedness begins as an interior orientation of the heart (cf. Ps 36:1–4, where the wicked "set no good thing before their eyes... they lie awake plotting wickedness") before expressing as social violence. The ANE wisdom tradition (Mesopotamian and Egyptian) also located the source of destructive behavior in the disordered heart.</p>',
    "3": '<p>"Their tongues are as sharp as a serpent\'s; viper venom is under their lips" — <em>ḥiddĕpû lĕšônām kĕmô nāḥāš</em> (they have sharpened their tongue like a serpent). The serpent-tongue imagery draws on the Genesis 3 narrative (the serpent\'s speech as the instrument of humanity\'s undoing) and the ANE wisdom tradition in which the tongue of the wicked is a deadly weapon. The same image appears in Ps 58:4 (the deaf cobra) and is cited by Paul in Romans 3:13 as part of his catena of OT texts demonstrating universal human guilt. <em>Selah</em> marks a pause to reflect on the severity of the threat.</p>',
    "4": '<p>"Keep me, O LORD, from the clutches of the wicked; preserve me from violent men who intend to make me stumble" — <em>mĕzammĕmû lidhôt peʿāmāy</em> (they plot to push aside my steps). The language of "pushing aside my steps" is a hunting metaphor: the prey is driven off the path and into the trap. The request for divine keeping (<em>šāmĕrênî</em>) and preservation (<em>nĕṣurênî</em>) uses the standard vocabulary of covenant protection — the same terms applied to the Torah\'s preservation of the righteous (Ps 119:11, 17) and to divine keeping of the traveler (Ps 121:7).</p>',
    "5": '<p>"The arrogant have laid a trap for me and stretched out cords; they have spread a net along my path and set snares" — the hunting imagery is elaborated: trap (<em>paḥ</em>), cords (<em>ḥăbālîm</em>), net (<em>rešet</em>), and snares (<em>môqĕšîm</em>) are the four implements of the fowler or hunter applied to the wicked surrounding the righteous. The same arsenal appears in Pss 9:15; 35:7–8; 57:6; 91:3; 141:9–10. The setting of elaborate hunting traps — hidden, covered, lying in wait on the exact path the prey walks — is the image for the calculated malice of those who pursue the righteous. <em>Selah</em>.</p>',
    "6": '<p>"I say to the LORD, \'You are my God\' — hear me, O LORD, and listen to my pleas for mercy" — the confession "you are my God (<em>ʾēlî ʾattāh</em>)" is the covenant declaration of loyalty, the inverse of the enemies\' malice. The same declaration appears in Ps 31:14 and is echoed in Ps 22:10 ("You have been my God from my mother\'s womb"). In the context of Psalms 140–144\'s sequence of prayer against enemies, this personal covenant confession grounds each prayer not in merit but in relationship.</p>',
    "7": '<p>"O Sovereign LORD, the strength of my salvation — you have shielded my head in the day of battle" — <em>ʾadonāy YHWH</em> (Sovereign LORD) — the double divine title emphasizing both lordship and covenant name. "The strength of my salvation (<em>ʿōz yĕšûʿātî</em>)" — salvation not as mere deliverance but as the divine power that accomplishes it. "Shielded my head in the day of battle (<em>sakōtāh lĕrōʾšî bĕyôm nešeq</em>)" — the military context: the shield that protects the head from sword blows. In the ANE warrior culture, the head was the most vulnerable and most honored part of the body; to protect the head was to preserve life and honor simultaneously.</p>',
    "8": '<p>"Do not give the wicked what they want, O LORD; do not let their evil plans succeed, or they will grow proud" — <em>al-tēn YHWH maʾăwiyyê rāšāʿ</em> (do not grant the desires of the wicked). The prayer restrains the enemy not only from their acts but from their desires being satisfied — since a satisfied enemy grows proud (<em>yārûmû</em>) and more dangerous. The logic of the imprecatory psalms is partly social-psychological: unanswered wickedness emboldens further wickedness, while divine intervention disrupts the cycle. <em>Selah</em>.</p>',
    "9": '<p>"Let the trouble caused by the words of those who hem me in fall back upon their own heads" — the principle of retributive return: the evil the enemies speak against the righteous should recoil upon themselves. This is the lex talionis applied to speech: words of harm returning to harm the speaker. The same principle appears in Ps 7:15–16 (the wicked "digs a pit and falls into it; his trouble returns to his own head") and Prov 26:27 ("Whoever digs a pit will fall into it"). The language of "those who hem me in (<em>mĕkabbāy</em>)" suggests besieging armies who surround the city or the prey with no escape.</p>',
    "10": '<p>"Let burning coals rain down on them; let them be thrown into the fire — into pits so deep they never rise" — the threefold imprecatory wish: burning coals (<em>gḥālîm</em>), fire (<em>ʾēš</em>), and deep pits (<em>maḥămōrôt</em>). Burning coals from heaven appear in theophanic contexts (Ps 18:13: "The LORD thundered from heaven... He shot arrows and scattered them; he hurled lightning bolts and routed them") — divine judgment expressed through natural forces deployed supernaturally. The "deep pits" echo the imagery of Sheol as the place from which none return (Ps 88:6; Isa 14:15). The imprecation asks for nothing more than the standard covenant curses — what YHWH swore he would do to covenant-breakers.</p>',
    "11": '<p>"Let no slander take root in the land; may evil relentlessly pursue the violent man until he falls" — <em>ʾîš lāšôn bal-yikkôn bāʾāreṣ</em> (a man of tongue will not be established in the land). <em>Lāšôn</em> (tongue/speech) stands metonymically for the slanderer and the violent speaker. The wisdom tradition holds that the slanderer destroys community (Prov 11:9; 16:28; 26:20–22). "Take root (<em>yikkôn</em>)" — the same verb used for the divine establishment of Zion and the Davidic throne; the slanderer\'s attempt at permanence is denied by the covenant structure of reality. The contrast: the righteous are established; the violent man is hunted down (<em>yĕṣûdennû</em>).</p>',
    "12": '<p>"I know that the LORD will uphold the cause of the oppressed and defend the rights of the poor" — the transition from imprecation to confident confession. "I know (<em>yādaʿtî</em>)" — the knowledge is not theological speculation but covenant testimony. "The cause of the oppressed (<em>dîn ʿānî</em>)" — <em>dîn</em> is a legal term for the formal adjudication of a case in court; YHWH is the divine judge who takes up the legal cause of those without human advocates (the <em>ʿānî</em>, the poor-and-lowly; and <em>ʾebyônîm</em>, the destitute). The Psalter consistently grounds the expectation of divine justice in covenant character (Ps 9:9; 10:14; 35:10; 72:4, 12–13; 82:3–4).</p>',
    "13": '<p>"Surely the righteous will give thanks to your name; the upright will live in your presence" — the psalm ends with a confident eschatological assertion rather than a resolved situation. "The upright will live in your presence (<em>yēšĕbû yĕšārîm et-pānêkā</em>)" — to dwell before the divine face is the ultimate covenant blessing (Num 6:25–26; Pss 11:7; 16:11; 17:15). The verb <em>yāšab</em> (to sit/dwell) echoes the throne-room language: the righteous have a permanent place in the divine presence, while the wicked are cast out. The psalm moves from peril (vv. 1–5) through prayer (vv. 6–11) to confidence (vv. 12–13).</p>',
  },
  "141": {
    "1": '<p>Psalm 141 opens with the urgency characteristic of the final Davidic cluster (Pss 138–145): "come quickly (<em>ḥûšāh</em>)!" — the same urgency-adverb found in Ps 70:1 ("Hurry, O God, to save me!"). The double cry — "I call on you" and "hear my voice when I cry out to you" — is not mere repetition but the standard Psalter prayer-stance: the initial address and the request for admission. In the temple liturgy, a worshipper would approach the gate with a cry that required acknowledgment before entrance was granted (Ps 24:3–5; 100:4).</p>',
    "2": '<p>"May my prayer rise before you like incense, and the lifting up of my hands like the evening offering" — <em>tikkôn tĕpillātî qĕṭōret lĕpānêkā</em>. The incense offering (<em>qĕṭōret</em>) was burned twice daily on the golden incense altar inside the tabernacle/temple (Exod 30:7–8) — at the morning and evening tamid. The <em>minḥāh</em> (evening grain offering) was the "evening sacrifice" at 3pm. The speaker\'s prayer and lifted hands are identified with these daily offerings — turning individual prayer into a liturgical participation in the ongoing temple worship even when physically absent from the temple. Revelation 8:3–4 takes up this imagery for heavenly intercession: the golden censer, the incense, and "the prayers of all the saints" rising before God.</p>',
    "3": '<p>"Post a guard at my mouth, O LORD; station a sentry at the door of my lips" — the metaphor of civic fortification applied to speech: the mouth as a gate that requires a guard to control who or what passes through. In the ANE city, gates were heavily defended and carefully controlled — the gate determined who entered, what goods came through, and what justice was dispensed (Ruth 4:1–11; Amos 5:12; Prov 31:23). The wisdom tradition is particularly alert to the danger of unguarded speech: "Those who guard their mouths preserve their lives; those who open wide their lips come to ruin" (Prov 13:3; cf. 21:23).</p>',
    "4": '<p>"Do not let my heart be drawn to anything evil — to take part in the wicked acts of evildoers, or to taste any of their pleasures" — <em>al-taṭ-libbî lĕdābār-rāʿ</em> (do not let my heart incline to an evil thing). The prayer for divine restraint of the heart reflects the Psalter\'s and wisdom tradition\'s understanding that the heart\'s inclination is not fully under the individual\'s control — it can be "drawn" or "inclined" by external forces and internal disorders. The prayer for a guarded mouth (v. 3) and a guarded heart (v. 4) together cover the two Proverbs 4:23–27 dimensions: "Above all else guard your heart... put away perversity from your lips."</p>',
    "5": '<p>"If a righteous man strikes me, I will take it as a kindness; if he rebukes me, it is like fine oil on my head — I will not refuse it" — the wisdom paradox of the beneficial rebuke. "Fine oil on the head (<em>šemen rōʾš</em>)" — in the ANE hospitality culture, anointing a guest\'s head with scented oil was a signal of welcome, honor, and special status (Ps 23:5; Luke 7:46). To accept another person\'s rebuke as if it were this prestigious anointing is to practice the highest wisdom disposition — treasuring correction over flattery. Proverbs returns to this theme repeatedly: "Better is open rebuke than hidden love. Faithful are the wounds of a friend; profuse are the kisses of an enemy" (Prov 27:5–6; cf. 9:8; 15:12; 25:12).</p>',
    "6": '<p>"When their leaders are hurled down from the cliffs, the people will find my words welcome" — a difficult verse. "Leaders (<em>šōpĕṭêhem</em>)" (their judges/rulers) hurled from cliffs may refer to the common ANE execution method for criminals and political enemies (2 Chr 25:12; Luke 4:29 — the crowd attempts this against Jesus at Nazareth). The sense seems to be: when the wicked rulers fall, the people will recognize that the words of the righteous speaker were true. This reflects the Psalter\'s eschatological confidence that vindication will come publicly.</p>',
    "7": '<p>"Like clods of earth turned up by the plowshare, our bones lie scattered at the brink of the grave" — <em>kĕmô pōlēaḥ ûbōqēaʿ bāʾāreṣ niplĕgû ʿăṣāmênû</em>. The agricultural image of broken clods of earth (from the plowing/splitting of the soil) applied to scattered bones is a visceral image of the community\'s extremity — scattered and exposed at the very mouth of Sheol (<em>lĕpî šĕʾôl</em>). The bones are the most permanent part of a person in the OT anthropology; scattered bones are the final indignity of death and defeat (Ps 53:5; Ezek 37:1–14).</p>',
    "8": '<p>"But my eyes are fixed on you, O Lord GOD — in you I shelter; do not leave me exposed" — <em>kî ʾēlêkā YHWH ʾadonāy ʿênāy</em> (for to you, LORD, my Lord, are my eyes). The fixed-eyes formula expresses exclusive attention and trust directed toward YHWH rather than toward the threatening forces. "Do not leave me exposed (<em>al-tĕʿar napšî</em>)" — <em>ʿārāh</em> (to lay bare, to pour out, to leave naked and unprotected) is the word for stripping and exposing; the soul (life) left naked is utterly vulnerable. The contrast with v. 7 (bones scattered, exposed at Sheol\'s mouth) is stark: the soul fixes its gaze upward while the body is threatened below.</p>',
    "9": '<p>"Keep me from the trap they have set for me, and from the snares that evildoers have laid" — the hunting-trap imagery returns (cf. Ps 140:5) — <em>paḥ</em> (trap) and <em>môqĕšôt</em> (snares). The repeated use of this imagery across Psalms 140–141 creates a thematic cluster: the righteous person is surrounded by hunters who have laid elaborate traps. The prayer for divine preservation from the trap is also a prayer for discernment — to see the hidden danger that the wicked have concealed in the ordinary path (Ps 91:3: "He will save you from the fowler\'s snare").</p>',
    "10": '<p>"Let the wicked tumble into their own nets while I escape unharmed" — the retributive principle stated succinctly: the nets set for the righteous become the nets in which the wicked are caught. This is the "boomerang justice" pattern of the Psalter (Pss 7:15–16; 9:15; 35:8; 57:6; Prov 26:27; 28:10). "While I escape unharmed (<em>yaḥad ʾănî ʾeʿĕbôr</em>)" — the simultaneous trapping of the wicked and the escape of the righteous is a single divine act. The psalm ends with confident anticipation rather than achieved deliverance — the prayer is still in progress, but its expected outcome is stated as certain.</p>',
  },
  "142": {
    "1": '<p>The superscription of Psalm 142 is one of the most historically specific in the Psalter: "A Maskil of David, a prayer composed when he was in the cave." Two cave episodes are associated with David in 1 Samuel: the Cave of Adullam (1 Sam 22:1–2), where David fled from Saul and was joined by 400 men, and the cave at En-gedi (1 Sam 24:3–22), where David had the opportunity to kill Saul but refrained. Both involve hiding from mortal danger with no human rescue in sight. "With full voice (<em>qôlî</em>)" — the emphasis on audible crying to YHWH, even in hiding, when quiet would be safer, suggests that this prayer is the desperate act of one who has abandoned all pretense of strategy and fallen back on YHWH alone.</p>',
    "2": '<p>"I pour out my troubles before him; I lay my distress before him" — <em>ʾešpōk lĕpānāyw śîḥî</em> (I pour out my complaint before him). The "pouring out" idiom for prayer appears in 1 Samuel 1:15, where Hannah says "I have been pouring out my soul before the LORD" (<em>šōpeket et-napšî</em>), and in Lamentations 2:19 ("pour out your heart like water before the face of the LORD"). The visceral image of liquid poured out suggests total self-disclosure — nothing held back, the entire content of the inner life offered to the divine listener. <em>Śîaḥ</em> (complaint, meditation, prayer) is related to the verb for "speaking" or "rehearsing" — the prayer is the spoken articulation of what had been roiling silently within.</p>',
    "3": '<p>"When my spirit grows faint within me, you know my way" — <em>bĕhitʿaṭṭēp ʿālay rûḥî wĕʾattāh yādaʿtā nĕtîbātî</em>. "Spirit grows faint (<em>hitʿaṭṭēp</em>)" — the word means to wrap oneself, to be covered over, faint; it appears also in Ps 61:2 ("when my heart is faint") and Ps 77:3 ("my spirit grows faint"). The confession "you know my way (<em>yādaʿtā nĕtîbātî</em>)" — the hidden path in the cave is known to YHWH even when the speaker cannot see it. Divine omniscience as the ground of prayer: the one who knows my hidden path knows the trap hidden in it (Ps 139:1–4).</p>',
    "4": '<p>"I look to my right — no one acknowledges me; all escape is cut off from me; not a soul cares for me" — the three-fold description of total abandonment: no acknowledgment (<em>ûmakîr</em>, no one recognizes me), no escape (<em>ʾābad mānôs mimmennî</em>, escape has perished from me), and no one who cares for my soul (<em>ʾên dôrēš lĕnapšî</em>, no one seeks after my soul). In ANE culture, the "right side" was the position of the advocate, the helper, the witness who would stand up for you in legal proceedings (Ps 109:31; 110:5). To have no one at your right is to have no one to defend you — a legal, social, and existential abandonment.</p>',
    "5": '<p>"I cry to you, O LORD; I say, \'You are my shelter and my portion in this living world\'" — <em>ḥelqî beʾereṣ haḥayyîm</em> (my portion in the land of the living). <em>Ḥēleq</em> (portion, share, lot) is the technical term for the tribal allotment of land in the conquest and settlement of Canaan (Josh 14:4; 15:13; 18:9); it is also used for the Levites, who have "no portion" of land because YHWH is their portion (Num 18:20; Deut 10:9; 18:1–2; Ps 16:5). To declare "you are my portion" is to claim the Levitical inheritance — having YHWH rather than land as the ground of existence. "Land of the living (<em>ʾereṣ haḥayyîm</em>)" — the counterpart to Sheol and the "land of forgetting" (Ps 88:12); the sphere of covenant life before YHWH.</p>',
    "6": '<p>"Hear my cry, for I have been brought very low; rescue me from those who pursue me, for they are too strong for me" — <em>kî dallôtî mĕʾōd</em> (for I have been brought very low, am very weak). <em>Dal</em> (weak, poor, lowly) is the social category of those without resources or power — not the moderate poverty of the <em>ʿānî</em> but extreme helplessness. "Too strong for me (<em>kî ʾāmĕṣû mimmennî</em>)" — the honest admission that the enemies are stronger than the speaker is the ground for the prayer: when human resources are exhausted, the appeal to divine power becomes the only option. The "prayer of the weak" is structurally central to the Psalter (Pss 34:6; 40:17; 70:5; 86:1; 109:22).</p>',
    "7": '<p>"Lead my soul out of this prison so I can praise your name. Then the righteous will gather around me, because you will have been generous to me" — <em>hôṣîʾāh mimmāsger napšî</em> (lead out my soul from the prison/enclosure). The cave has become a prison — the hiding place that was refuge is also confinement. The liberation sought is not merely physical escape but the restoration of the capacity for praise (<em>lĕhôdôt ʾet-šĕmekā</em>) and communal worship (the righteous gathering around the delivered person). The psalm ends with a vision of restored community: the one who prayed in utter isolation (<em>v. 4</em>: "not a soul cares for me") will be surrounded by the righteous. Liberation from the cave enables the gathering of a congregation.</p>',
  },
  "143": {
    "1": '<p>Psalm 143 is one of the seven classical Penitential Psalms designated in the liturgical tradition of the Western Church (Pss 6, 32, 38, 51, 102, 130, 143). The opening petition appeals to divine faithfulness (<em>ʾĕmûnāh</em>) and righteousness (<em>ṣĕdāqāh</em>) as the grounds for divine answer — not the speaker\'s merit. "In your faithfulness and righteousness, answer me" — the remarkable request that YHWH\'s own character attributes (<em>ʾĕmûnāh</em> and <em>ṣedeq</em>) become the grounds of rescue; the same attributes that could condemn the wicked are here appealed to for salvation of the penitent. This captures the paradox of grace: divine righteousness that punishes sin also delivers those who acknowledge their guilt.</p>',
    "2": '<p>"Do not bring your servant into judgment, for no one alive can stand as righteous before you" — <em>kî lōʾ yiṣdaq lĕpānêkā kol-ḥāy</em> (for no living person is righteous before you). This is the starkest universal-guilt statement in the Psalter — more sweeping than Ps 14:1–3 ("there is no one who does good, not even one"), since it applies to "any living person" without exception. Paul cites this verse in Romans 3:20 and Galatians 2:16 as the foundation for his argument that justification is not by works of the law: "By works of the law no one will be justified." The verse becomes for Paul the OT\'s own recognition that the covenant\'s demands exceed any human\'s capacity to meet them.</p>',
    "3": '<p>"For the enemy has hunted me down and crushed my life to the ground; he has forced me to dwell in darkness like those who died long ago" — <em>yōšib bĕmaḥăšakkîm kĕmētê ʿôlām</em> (he has forced me to dwell in darkness like those long dead). "Forced me to dwell in darkness like those long dead" — the imagery of being thrust into Sheol\'s conditions while still alive: the long dead (<em>mētê ʿôlām</em>) are those whose names have been forgotten, who no longer inhabit the community of the living. Being made to "dwell in darkness" while alive echoes Ps 88 — the condition of being in Sheol before biological death, the living experience of covenant abandonment.</p>',
    "4": '<p>"So my spirit grows faint within me; my heart within me is filled with dismay" — <em>rûḥî ʿālay tittʿaṭṭēp</em> (my spirit within me grows faint) — the same verb as Ps 142:3. "My heart within me is filled with dismay (<em>bĕtôkî yiššômēm libbî</em>)" — <em>šāmēm</em> (desolate, appalled, stunned) is the word used for the desolation of the destroyed temple (Lam 1:4, 13, 16) and of ravaged land (Jer 12:11; Isa 54:1). The heart is desolated as completely as a bombed landscape. The Babylonian exile background of these psalms is palpable: the language of individual distress borrows the vocabulary of national catastrophe.</p>',
    "5": '<p>"I call to mind the days of old; I meditate on all you have done; I reflect on the work of your hands" — <em>zākartî yāmîm miqqedem hāgîtî bĕkol-paʿālĕkā</em>. The practice of memorial meditation — deliberately calling to mind the covenant acts of the past — is one of the Psalter\'s primary resources for faith under pressure. Psalms 77:11–12 uses the same practice: "I will remember the deeds of the LORD; yes, I will remember your wonders of old. I will meditate on all your work and muse on your mighty deeds." The Passover seder makes this a communal liturgical act: "In every generation, each person is obligated to see themselves as if they personally left Egypt." The past becomes present through intentional memory.</p>',
    "6": '<p>"I reach out my hands toward you; my whole being longs for you like a land parched for rain" — the two postures of prayer: reaching hands toward YHWH (the standard upward-extended-hands prayer gesture; Pss 28:2; 63:4; Lam 1:17; 2:19) and the thirst-image for longing (Ps 42:1–2: "As a deer pants for streams of water, so my soul pants for you, O God"; Ps 63:1: "my soul thirsts for you, my flesh longs for you, as in a dry and weary land where there is no water"; Isa 44:3; 55:1). The parched land that longs for rain is the desert landscape of Israel — the absolute dependency on rainfall as a divine gift makes the rain-longing a powerful image of total dependence. <em>Selah</em>.</p>',
    "7": '<p>"Answer me quickly, O LORD — my spirit is failing! Do not hide your face from me, or I will be like those who sink into the grave" — the urgency adverb "quickly (<em>māhēr</em>)" reflects the medical-emergency character of the prayer: delay is lethal. "Do not hide your face (<em>al-tastēr pānêkā</em>)" — the hidden divine face is the most severe form of divine silence in the Psalter (Pss 13:1; 22:24; 27:9; 44:24; 88:14; 89:46; Isa 59:2; 64:7; Ezek 39:23–24). "Like those who sink into the grave (<em>kĕyōrĕdê bôr</em>)" — the same pit-descent formula as Ps 88:4; 143:3. Divine absence and death are causally linked: the hidden face produces the descent into the pit.</p>',
    "8": '<p>"Let me hear of your steadfast love in the morning, for in you I put my trust; show me the path I should take, for I lift my soul to you" — "in the morning (<em>babbōqer</em>)" — the morning as the time of divine answer is a recurring motif in the Psalter: the worshipper kept a night vigil waiting for the morning oracle of divine favor and deliverance (Pss 5:3; 46:5; 90:14; 130:5–6; Lam 3:22–23). The morning after the night of suffering is the expected moment of divine ḥesed announcement. "Show me the path (<em>hôdîʿênî derekî-zû ʾēlēk bāh</em>)" — the path-metaphor unites guidance, wisdom, and covenant: to be shown the right path by YHWH is to receive both practical direction and moral formation.</p>',
    "9": '<p>"Rescue me from my enemies, O LORD — I run to you for shelter" — <em>ʾêlêkā kissîtî</em> (to you I have hidden myself, I have taken shelter). The verb <em>kāsāh</em> means to cover, hide, conceal — the speaker has covered themselves with YHWH as one hides under a cloak or in a cave. The divine name/presence itself becomes the hiding place (Ps 27:5: "For in the day of trouble he will conceal me in his shelter; in the secret of his tent he will hide me"; Ps 31:20: "In the shelter of your presence you hide them"). The cave of v. 142 has given way to the divine presence itself as the ultimate shelter.</p>',
    "10": '<p>"Teach me to do your will, for you are my God; may your good Spirit lead me on a level path" — <em>rûḥăkā ṭôbāh tanḥēnî bĕʾereṣ mîšôr</em> (your good Spirit will lead me on a level land/plain). "Good Spirit (<em>rûaḥ ṭôbāh</em>)" — one of only three OT occurrences: here, Nehemiah 9:20 ("You gave your good Spirit to instruct them"), and the implied reference in Isaiah 63:10–11. The Spirit as the agent of divine guidance "on a level path" (the opposite of the rough and trap-filled path of vv. 3–4) frames the Spirit\'s work as guidance into covenant obedience and safety. "Level path (<em>ʾereṣ mîšôr</em>)" — the opposite of the perilous terrain; the plain where walking is safe and clear.</p>',
    "11": '<p>"For the sake of your name, O LORD, keep me alive; in your righteousness lead my soul out of its distress" — <em>lĕmaʿan-šĕmĕkā YHWH tĕḥayyênî</em> (for the sake of your name, O LORD, give me life). The appeal to the divine name as the ground of rescue is the highest appeal: YHWH\'s own reputation, character, and self-disclosure are at stake in how he treats the speaker. Similar appeals appear in Ps 23:3 ("he leads me in paths of righteousness for his name\'s sake"), Ps 25:11 ("for the sake of your name, O LORD, pardon my guilt"), Ezek 36:22–23, and John 12:28 ("Father, glorify your name"). When the righteous suffer without rescue, the divine name is compromised.</p>',
    "12": '<p>"And in your steadfast love silence my enemies and put an end to all who oppress me — for I am your servant" — <em>ûbĕḥasdĕkā tạṣmît ʾōyĕbāy</em> (and in your ḥesed destroy my enemies). The final appeal is to <em>ḥesed</em> — the covenant loyalty that requires the protection of covenant members and the judgment of covenant-breakers. "For I am your servant (<em>kî ʿabdĕkā ʾānî</em>)" — the last word of the psalm is the covenant status that grounds the entire prayer: servant-relationship entitles the speaker to the Master\'s protection. The Penitential Psalms generally end not with resolution but with petition — the situation remains unresolved, but the speaker\'s covenant identity remains firm.</p>',
  },
  "144": {
    "1": '<p>Psalm 144 opens with a beatitude-like blessing formula applied to YHWH: "Blessed is the LORD (<em>bārûk YHWH</em>) my rock." The divine warrior who "trains my hands for war and my fingers for battle" echoes Psalm 18:34 ("He trains my hands for battle; my arms can bend a bow of bronze"), making Ps 144 a deliberate echo and reworking of Ps 18 (cf. also vv. 5–7 echoing Ps 18:7–16). The king-warrior who receives divine training for battle is the ANE royal ideal: the monarch\'s military competence was understood as divinely bestowed, not merely human achievement. Egyptian and Mesopotamian royal inscriptions regularly attribute victories to divine instruction in warfare.</p>',
    "2": '<p>"He is my steadfast love and my fortress, my high tower and my deliverer, my shield and the one in whom I trust, who subdues peoples under me" — the seven-fold accumulation of military-protection metaphors: steadfast love (<em>ḥasdî</em>), fortress (<em>mĕṣûdātî</em>), high tower (<em>miśgabbî</em>), deliverer (<em>mĕpalṭî</em>), shield (<em>māginnî</em>), the one I trust (<em>bô ḥāsîtî</em>), and subduer of peoples (<em>hārôdēd ʿammî taḥtāy</em>). The beginning with <em>ḥesed</em> (steadfast love) as the first military metaphor is remarkable: covenant loyalty is framed as protective armor. The ANE king typically listed military titles for his patron deity; this psalm places the covenant attribute first, making <em>ḥesed</em> the foundation of all military capability.</p>',
    "3": '<p>"LORD, what is a human being that you take notice of him, or the son of man that you think of him?" — <em>mā-ʾādām wattēdāʿēhû ben-ʾĕnôš wattĕḥaššĕbēhû</em>. This verse borrows almost verbatim from Psalm 8:4 ("What is man that you are mindful of him, and the son of man that you care for him?"), but with a subtle shift: in Ps 8, the question leads to an astonished affirmation of human dignity (v. 5: "you have made him a little lower than the heavenly beings and crowned him with glory and honor"). In Ps 144, the same question leads to the brevity and transience of human life (v. 4). The royal psalm uses the humility of Ps 8 without its exaltation — a theological move of kenotic leadership.</p>',
    "4": '<p>"A human being is like a breath; his days pass like a shadow" — <em>ʾādām lahebel dāmāh yāmāyw kĕṣēl ʿōbēr</em>. <em>Hebel</em> (breath, vapor, vanity) is the central term of Ecclesiastes (appearing 38 times in Qohelet). The fleeting character of human life is a wisdom observation, not a counsel of despair — it contextualizes the royal warrior\'s accomplishments within a frame of divine dependence. <em>Ṣēl ʿōbēr</em> (a passing shadow) — the shadow that moves across the ground as the sun moves is the image of swift, irreversible passage (Job 8:9; 14:2; Ps 102:11; 109:23; Eccl 6:12; 8:13). The warrior-king is great, but he is "a breath."</p>',
    "5": '<p>"Bow your heavens, LORD, and come down; touch the mountains so that they smoke" — the theophany request: <em>haṭ-šāmêkā YHWH wĕtēraḏ</em> (bend/bow your heavens and descend). This is the vocabulary of the Sinai theophany and the divine warrior tradition: Exodus 19:18 ("Mount Sinai was covered with smoke, because the LORD descended on it in fire"); Ps 18:9–12 ("He parted the heavens and came down; dark clouds were under his feet. He mounted the cherubim and flew; he soared on the wings of the wind"). The smoking mountains are the physical sign that divine fire has touched earthly matter — the boundary between heaven and earth has been crossed by divine descent.</p>',
    "6": '<p>"Send out lightning and scatter them; shoot your arrows and put them to flight" — the divine warrior\'s weapons: lightning (<em>bĕrāqîm</em>) and arrows (<em>ḥiṣṣêkā</em>). In the ANE warrior mythology and in the biblical theophany tradition, lightning is both the weapon of the storm god and the arrow shot by the divine archer (Ps 18:14; 77:17; 78:48; 144:6; Job 36:32; 37:3; 38:35; Zech 9:14). The thunder/lightning combination is the classic "storm theophany" that the biblical tradition inherited and transformed: YHWH uses the storm as his chariot, his weapons, and his appearance to his enemies.</p>',
    "7": '<p>"Reach down your hand from above; rescue me and deliver me from the overwhelming waters, from the hand of foreigners" — <em>šĕlaḥ yādêkā mimmārôm</em> (send your hand from above). The "hand from above" reaching down to rescue is the reverse image of the hand reaching up from the drowning (Ps 18:16: "He reached down from on high and took hold of me; he drew me out of deep waters"). "Overwhelming waters (<em>mayim rabbîm</em>)" — the primordial chaos water, the sea that threatens to swallow (Pss 18:16; 46:3; 69:14–15; 93:4; Jon 2:3). "Hand of foreigners (<em>yad bĕnê nēkār</em>)" — a technical term for non-Israelites whose covenant loyalty is absent.</p>',
    "8": '<p>"whose mouths speak emptiness and whose right hand is a hand of deception" — <em>ʾăšer pîhem dibber-šāwʾ ûymînām yĕmîn šāqer</em>. <em>Šāwʾ</em> (emptiness, vanity, falsehood) is also the word in the third commandment (Exod 20:7: "you shall not take the name of the LORD your God in vain/<em>šāwʾ</em>"). "Right hand of deception (<em>yĕmîn šāqer</em>)" — the right hand was the hand of oath, covenant, and loyal dealing in the ANE (Ps 89:13; Gen 48:14–18; Isa 62:8). A false right hand is the quintessential betrayal: the hand that ought to bind covenant instead enacts deception. The enemies fail at the most fundamental level of ANE social trust.</p>',
    "9": '<p>"I will sing a new song to you, O God; on a ten-stringed instrument I will sing your praise" — <em>šîr ḥādāš ʾāšîrāh lāk</em> (a new song I will sing to you). The "new song" (<em>šîr ḥādāš</em>) in the Psalter is the eschatological song of victory — sung when YHWH has acted decisively in salvation (Pss 33:3; 40:3; 96:1; 98:1; 144:9; 149:1; Isa 42:10; Rev 5:9; 14:3). The newness is not stylistic novelty but the fresh praise demanded by a new divine act. "Ten-stringed instrument (<em>nābel ʿāśôr</em>)" — the ten-stringed psaltery mentioned also in Pss 33:2 and 92:3; a specific instrument in the Levitical temple orchestra.</p>',
    "10": '<p>"who gives victory to kings and rescues his servant David from the deadly sword" — the transition from the "new song" promise (v. 9) to the historical ground for it: YHWH who gave victory to kings in the past is the YHWH who will rescue "his servant David." "Servant David (<em>ʿabdô dāwid</em>)" — the royal covenant title: David as YHWH\'s chosen servant is the representative of the community in whom the covenant promises are concentrated (2 Sam 7:5, 8, 19–29; Ps 89:3, 20, 39; Isa 37:35; 38:5).</p>',
    "11": '<p>"Deliver me and rescue me from the hand of foreigners, whose mouths speak emptiness and whose right hand is a hand of deception" — the near-verbatim repetition of vv. 7–8 creates a refrain structure around the central petition. The repetition is not redundancy but liturgical intensification — in the Psalter\'s poetics, the repeated refrain marks the central concern of the prayer. The "foreigners" whose speech is empty (<em>šāwʾ</em>) and whose right hand is false (<em>šāqer</em>) are contrasted with YHWH, whose right hand is true and whose name is not taken in vain.</p>',
    "12": '<p>"May our sons be like vigorous plants in their youth; may our daughters be like carved corner pillars of a palace" — the blessing catalogue of vv. 12–15 shifts from individual royal petition to communal prosperity. "Vigorous plants (<em>kĕnĕṭîʿîm mĕguddalîm bĕnaʿûrêhem</em>)" — seedlings that have grown to fullness in their youth; the agricultural metaphor for human flourishing. "Corner pillars of a palace (<em>zāwiyyôt mĕḥuṭṭābôt tĕbûnît hêkāl</em>)" — the carved corner-pillar (or caryatid column) was an architectural element of prestige in the ANE palace — a structural support that is also a work of art. Daughters described as load-bearing architectural elements of a palace is a remarkably dignified image in the ancient world.</p>',
    "13": '<p>"may our storehouses be full with every kind of supply; may our flocks produce thousands and ten thousands in our open country" — <em>mĕzāwênû mĕlêʾîm</em> (our storehouses full) — the full granary as covenant blessing (Deut 28:8: "The LORD will command the blessing on you in your barns"; Joel 2:24; Prov 3:10). "Ten thousands (<em>rĕbābôt</em>)" in the open country (<em>ḥûṣôt</em>) — the flock-multiplication formula is the typical covenant prosperity expression (Deut 7:13; 28:4, 11; Ps 65:13). The blessing catalogue deliberately inverts the covenant curses of Deuteronomy 28:15–68.</p>',
    "14": '<p>"may our cattle be well-fitted for labour; may there be no breach and no exile, no cry of distress in our streets" — <em>ʾallûpênû mĕsubbālîm</em> (our cattle, ox-leaders, are laden/strong for work). "No breach (<em>pereṣ</em>) and no exile (<em>yôṣēʾt</em>)": <em>pereṣ</em> is the gap or breach in a city wall through which enemies enter (Isa 30:13; Amos 4:3; Neh 6:1); <em>yôṣēʾt</em> refers to the exile of the population in defeat. "No cry of distress (<em>ṣĕwāḥāh</em>) in our streets" — the <em>ṣĕʿāqāh</em>/<em>ṣĕwāḥāh</em> (outcry) was the emergency call for justice from those in distress (Gen 18:20–21; 19:13; Exod 2:23; 3:7, 9; 22:22–24; Isa 5:7). A community without this outcry is one where covenant justice is working.</p>',
    "15": '<p>"Blessed are the people for whom it is so; blessed are the people whose God is the LORD" — the double beatitude concluding the blessing catalogue. "Blessed (<em>ʾašrê</em>) are the people for whom it is so (<em>šekkākāh lô</em>)" — the beatitude of material covenant blessing. "Blessed are the people whose God is the LORD" — this second beatitude lifts the material blessing into its proper frame: the material covenant prosperity is the fruit of the covenant relationship, not its goal or condition. The primary blessing is not the storehouses but YHWH himself. The formula echoes Ps 33:12 ("Blessed is the nation whose God is the LORD, the people he chose for his inheritance").</p>',
  },
  "145": {
    "1": '<p>Psalm 145 carries the unique superscription <em>Tĕhillāh lĕdāwid</em> — "A Praise of David." <em>Tĕhillāh</em> (Praise, hymn of praise) is the singular form of <em>Tĕhillîm</em> — the Hebrew name for the entire book of Psalms. Ps 145 is thus in some sense the book\'s defining psalm, the one that names the whole collection. "I will exalt you, my God and King (<em>ʾĕlōhay hammelek</em>)" — the title "King" for YHWH is the distinctive claim of the enthronement psalms and of Ps 145 in particular, which develops the divine kingdom (vv. 11–13) as the psalm\'s central theological theme. The promise "I will bless your name forever (<em>lĕʿôlām waʿed</em>)" frames the entire acrostic: from aleph to taw, for eternity.</p>',
    "2": '<p>"Every day I will bless you and praise your name forever and ever" — the temporal extension of praise: "every day (<em>bĕkol-yôm</em>)" and "forever (<em>lĕʿôlām waʿed</em>)" together span the full scope of time. The rabbinic tradition developed from Ps 145 the practice of reciting it three times daily — morning, afternoon, and evening — as a fundamental act of Jewish piety. The Babylonian Talmud (Berakhot 4b) states: "Whoever recites Tĕhillāh lĕdāwid three times each day is assured of a place in the world to come." The psalm\'s structure (acrostic covering all 22 Hebrew letters) supports its reputation as an all-encompassing praise.</p>',
    "3": '<p>"The LORD is great and highly to be praised; his greatness no one can search out" — <em>wĕligdūlātô ʾên ḥēqer</em> (and his greatness has no searching out). The unsearchable divine greatness is an ANE theological commonplace (cf. the Mesopotamian hymns to Marduk and Shamash), but in the Psalter it becomes specifically the greatness of covenant acts — the <em>gĕdullāh</em> (greatness/greatness-in-deed) that Israel has witnessed in the exodus and settlement. "No searching out (<em>ʾên ḥēqer</em>)" — the same phrase used of the divine understanding in Isaiah 40:28 ("his understanding no one can fathom") and in Job 5:9 (the unsearchable wonders of God).</p>',
    "4": '<p>"One generation will commend your works to the next and declare your mighty deeds" — <em>dôr lĕdôr yĕšabbaḥ maʿăśêkā</em> (generation to generation will praise your works). The intergenerational transmission of covenant memory is a fundamental Psalter and Deuteronomic concern: Ps 78:1–8 ("we will tell the next generation the praiseworthy deeds of the LORD"); Deut 6:20–25 (children ask about the statutes and are told the Exodus story); Ps 102:18 ("let this be written for a future generation"). The "mighty deeds (<em>gĕbûrōt</em>)" are the acts of divine power — especially the Exodus and covenant-history events — that are the content of this generational transmission.</p>',
    "5": '<p>"I will speak of the splendor of your glorious majesty and of your wonderful deeds" — <em>hădār kĕbôd hôdekā</em> (the splendor of the glory of your majesty) — three near-synonyms for divine majesty stacked together. <em>Hādār</em> (splendor, beauty, honor), <em>kābôd</em> (glory, weight, honor), and <em>hôd</em> (majesty, splendor) together create a superlative of superlatives — the most intense possible expression of divine glory. In the ANE royal court, the king\'s splendor was displayed in his clothing, his throne, his processions, and his palace; the psalm applies all of this vocabulary to YHWH, and then intensifies it beyond any earthly analogy.</p>',
    "6": '<p>"People will speak of the power of your awe-inspiring acts, and I will tell of your greatness" — the two subjects of praise in v. 6 — "people (<em>wĕʿûzuz</em> — the force/power of your terrible acts)" and "I (<em>wĕʾăsappĕrennāh</em>)" — create a movement between communal and individual witness. The "awe-inspiring acts (<em>nôrĕʾōtêkā</em>)" are the terrifying interventions of divine power in history — the plagues, the crossing of the sea, the conquest — that produced both fear in the nations and worship in Israel.</p>',
    "7": '<p>"They will overflow with praise for your great goodness and sing aloud of your righteousness" — <em>zēker rab-ṭûbĕkā yaббîʿû</em> (they will overflow/pour out the memory of your great goodness). The verb <em>nābaʿ</em> (to bubble up, overflow, gush) suggests an uncontainable abundance — the praise that cannot be contained. "Great goodness (<em>rab-ṭûb</em>)" — <em>ṭôb</em> (good, goodness, prosperity) in its fullest sense encompasses both moral goodness and the material abundance that flows from YHWH\'s generosity. "Your righteousness (<em>ṣidqātĕkā</em>)" — the divine righteousness that establishes what is right and acts to bring it about in the covenant community.</p>',
    "8": '<p>"The LORD is gracious and compassionate, slow to anger and rich in steadfast love" — <em>ḥannûn wĕraḥûm YHWH ʾerek ʾappayim ûgĕdal-ḥāsed</em>. The fourth appearance of the Sinai self-revelation formula (Exod 34:6) in Psalms 86–145 (also appearing in Pss 86:15; 103:8; 111:4; 112:4; 116:5; 145:8). Psalm 145\'s acrostic structure places this formula at the <em>ḥeth</em>-verse (v. 8), suggesting the psalmist deliberately positioned the central divine character confession within the alphabetic praise. In rabbinic tradition, this verse became one of the "Thirteen Attributes" (<em>Middot</em>) of God recited in liturgy, especially on Yom Kippur.</p>',
    "9": '<p>"The LORD is good to all; his compassion extends over all he has made" — <em>ṭôb YHWH lakkōl wĕraḥămāyw ʿal-kol-maʿăśāyw</em>. The universal scope of divine goodness and compassion — "to all (<em>lakkōl</em>)" and "over all he has made (<em>ʿal-kol-maʿăśāyw</em>)" — is a striking extension of covenant character to all creatures, not merely to Israel. The Psalter\'s universalism reaches its clearest expression here: YHWH\'s <em>raḥămîm</em> (compassion — from <em>reḥem</em>, womb) extends over the full creation. This verse was cited by early church fathers as evidence of divine common grace and is foundational for Jewish and Christian theologies of creation-care.</p>',
    "10": '<p>"All your works will praise you, LORD, and your devoted ones will bless you" — <em>yôdûkā YHWH kol-maʿăśêkā wăḥăsîdêkā yĕbārĕkûkā</em>. Two rings of praise: all creation (all your works) in the outer ring, and the <em>ḥăsîdîm</em> (devoted ones, those characterized by covenant loyalty) in the inner ring. The <em>ḥăsîdîm</em> are the community of those who reflect YHWH\'s own <em>ḥesed</em> back to him in worship and toward neighbor in action. Their blessing is not merely the passive praise of creation but the active, intentional declaration of the covenant community who know what they are praising.</p>',
    "11": '<p>"They will speak of the glory of your kingdom and tell of your power" — the middle section of Psalm 145 (vv. 11–13) is the theological heart of the psalm: the divine kingdom (<em>malkût</em>). "Glory of your kingdom (<em>kĕbôd malkûtekā</em>)" — <em>malkût</em> (kingdom, kingship, rule) becomes the central term: YHWH as king is not merely a metaphor but the foundational political claim of Israel\'s theology. All earthly kings are derivative of and accountable to this kingship. The NT\'s proclamation "the kingdom of God has come" (Mark 1:15) is unintelligible without this OT substrate.</p>',
    "12": '<p>"to make known to all humanity your mighty deeds and the majestic glory of your kingdom" — the purpose clause: the witness of the <em>ḥăsîdîm</em> is not merely internal community praise but external proclamation "to all humanity (<em>lĕbĕnê hāʾādām</em>, to the children of adam)." The theological vision of Ps 145 is therefore both doxological (praise to YHWH) and missional (proclamation to the nations). The "majestic glory of his kingdom (<em>ûkĕbôd hădār malkûtô</em>)" echoes the triple-glory language of v. 5 — the kingdom possesses the same superlative glory as the King.</p>',
    "13": '<p>"Your kingdom is an everlasting kingdom, and your dominion endures through all generations" — <em>malkûtĕkā malkût kol-ʿōlāmîm ûmemšaltĕkā bĕkol-dôr wādôr</em> (your kingdom is a kingdom of all ages; your dominion in every generation and generation). The Dead Sea Scrolls version (11QPsᵃ) adds at this point a <em>nun</em>-verse that is absent from the MT: "God is faithful in his words and holy in all his works" — reflecting either a scribal omission in the MT tradition or an alternate text. The LXX also has this verse. The kingdom\'s eternity is the counterpoint to human transience (v. 4: "his days pass like a shadow") — the kingdom lasts precisely what the human leader does not.</p>',
    "14": '<p>"The LORD upholds all who are falling and lifts up all who are brought low" — <em>sômēk YHWH lĕkol-hahannōfĕlîm wĕzôqēp lĕkol-hakkĕpûpîm</em>. The two participles — "those who are falling (<em>nōfĕlîm</em>)" and "those who are brought low (<em>kĕpûpîm</em>)" — describe those on the way down. YHWH "upholds (<em>sômēk</em>)" and "lifts up (<em>zôqēp</em>)" them — the two verbs of divine intervention at the point of collapse. This verse became liturgically significant: the Jewish <em>Amidah</em> prayer contains the blessing <em>Mĕḥayyē haMētîm</em> (who revives the dead), which draws on the logic of this verse — the God who lifts those who have fallen can also raise the dead.</p>',
    "15": '<p>"The eyes of all look to you, and you give them their food in due season" — <em>ʿênê-kōl ʾēlêkā yĕśabbērû wĕʾattāh nôtēn-lāhem et-ʾoklām bĕʿittô</em>. The image of all creatures looking expectantly toward YHWH for their food is a creation-theology statement about universal dependence. "In due season (<em>bĕʿittô</em>)" — the seasonal gift of food; YHWH provides within the created order of seasons and harvests, not through continuous miracle but through faithful creation-management. This verse and the next (v. 16) are used as grace before meals in Jewish practice, chosen because they express the theological meaning of eating: receiving from the open hand of the creator.</p>',
    "16": '<p>"You open your hand and satisfy the desire of every living thing" — <em>pôtēaḥ et-yādekā ûmaśbîaʿ lĕkol-ḥāy rāṣôn</em> (you open your hand and satisfy every living thing\'s desire). "Open your hand" — the divine generosity expressed as an open, giving hand (the inverse of the closed or grabbing hand of the oppressor). <em>Rāṣôn</em> (desire, goodwill, favor) — each creature\'s appropriate desire is satisfied; the word carries overtones of covenantal goodwill. The created order is not a system of competition for scarce resources but a field of divine generosity in which YHWH\'s open hand provides for all. Psalm 104:27–28 uses the same image: "All creatures look to you to give them their food at the proper time. When you give it to them, they gather it up."</p>',
    "17": '<p>"The LORD is righteous in all his ways and faithful in all his works" — <em>ṣaddîq YHWH bĕkol-dĕrākāyw wĕḥāsîd bĕkol-maʿăśāyw</em>. This verse is close to the missing <em>nun</em>-verse of v. 13a in the Dead Sea Scrolls version; the similarities suggest textual relationship. "Righteous in all his ways (<em>bĕkol-dĕrākāyw</em>)" — the totality-formula ("in all") appears five times in vv. 13–20, creating a cumulative universalism. <em>Ḥāsîd</em> applied to YHWH himself — YHWH as the one who practices <em>ḥesed</em>. The <em>ḥăsîdîm</em> (v. 10) model themselves on a God who is himself <em>ḥāsîd</em>.</p>',
    "18": '<p>"The LORD is near to all who call on him, to all who call on him in sincerity" — <em>qārôb YHWH lĕkol-qōrĕʾāyw lĕkol ʾăšer yiqrāʾûhû beʾĕmet</em>. "Near to all who call (<em>qārôb lĕkol-qōrĕʾāyw</em>)" — divine nearness as the answer to prayer; the God who is enthroned in the heavens (Pss 113:5; 123:1) is simultaneously near to the one who calls (Deut 4:7: "What other nation is so great as to have their gods near them the way the LORD our God is near us whenever we pray to him?"). "In sincerity (<em>beʾĕmet</em>)" — in truth, faithfulness, with integrity of intention; prayer from the lips only without the heart is not true calling on YHWH (Isa 29:13; Matt 15:8).</p>',
    "19": '<p>"He fulfills the desire of those who fear him; he hears their cry and saves them" — <em>yirʾāt ʾōtô</em> (the fear/reverence of him). The "fear of the LORD (<em>yirʾat YHWH</em>)" is the wisdom tradition\'s foundational disposition — the right orientation toward the Creator that produces moral formation, practical wisdom, and covenant loyalty (Prov 1:7; 9:10; 14:27; Ps 111:10; Eccl 12:13). Those who fear YHWH are the same as the <em>ḥăsîdîm</em> of v. 10 — the community shaped by covenant reverence whose desires YHWH fulfills. The desires of the fearers are not arbitrary wishes but the covenant-formed longings of those whose desires have been shaped by relationship with YHWH.</p>',
    "20": '<p>"The LORD guards all who love him, but he will destroy all the wicked" — the binary division of humanity in the Psalter\'s moral vision: those who love YHWH (<em>ʾōhăbāyw</em>) are guarded; the wicked (<em>rĕšāʿîm</em>) are destroyed. "Guards (<em>šômēr</em>)" — the covenant protection promised to those within covenant relationship (Ps 121:7–8; 127:1; 145:20). "Destroy (<em>yašmîd</em>)" — the covenant judgment on those outside covenant relationship. The sharp binary is not cruel but structurally necessary: a moral universe where YHWH reigns must ultimately distinguish between covenant loyalty and covenant-breaking.</p>',
    "21": '<p>"My mouth will speak the praise of the LORD, and let all living things bless his holy name forever and ever" — the psalm ends as it began: with the speaker\'s personal praise (v. 1: "I will exalt you") and then universalizes it to "all living things (<em>kol-bāśār</em>, all flesh)." The acrostic that covered every letter of the Hebrew alphabet is now extended to every creature — the alphabetic completion of praise points toward the cosmic completion. "Forever and ever (<em>lĕʿôlām waʿed</em>)" — the temporal frame that matches the eternal scope of the kingdom (v. 13). The psalm whose Hebrew name names the whole book ends with a vision of all flesh praising YHWH\'s holy name eternally.</p>',
  },
  "146": {
    "1": '<p>Psalm 146 opens the grand Hallel finale of the Psalter (Pss 146–150), five psalms all beginning and ending with <em>hallĕlû-Yāh</em> (Praise the LORD!). This doxological finale represents the Psalter\'s final movement: from lament (many psalms in Books I–IV) through instruction and wisdom (Ps 119) and the Songs of Ascent (Pss 120–134) to pure praise that increasingly loses its personal and historical specificity and becomes the eschatological voice of all creation. "Praise the LORD, O my soul (<em>hallĕlî napšî et-YHWH</em>)!" — the self-address in praise, urging one\'s own soul to praise; the same formula opens Ps 103 and 104, suggesting this cluster was shaped as a sequence.</p>',
    "2": '<p>"I will praise the LORD all my life; I will sing praises to my God as long as I live" — the two time-spans: "all my life (<em>bĕḥayyāy</em>)" and "as long as I live (<em>bĕʿôdî</em>, while I still exist)." The vow to praise for the entire duration of life is one of the Psalter\'s characteristic commitments (Pss 63:4; 104:33). In the context of vv. 3–4 (the mortality of princes), the vow to praise "all my life" is framed by the recognition that life is limited — the vow covers exactly as much time as one has, not more. The contrast with "all generations (<em>lĕdôr wādôr</em>, v. 10)" makes the human lifetime modest within the eternal divine reign.</p>',
    "3": '<p>"Do not put your trust in princes or in any human being, for there is no salvation in them" — <em>al-tibĕṭĕḥû bĕndîbîm bĕben-ʾādām ʾăšer ʾên lô tĕšûʿāh</em>. The anti-patronage principle. In the ANE patron-client social system, attaching oneself to a powerful <em>nādîb</em> (noble, prince, generous one) was the standard route to protection, resources, and advancement. The entire social order was organized around patron hierarchies. The psalm inverts this: there is "no salvation (<em>tĕšûʿāh</em>)" in any human patron, however powerful. <em>Tĕšûʿāh</em> (salvation, deliverance, victory) is specifically a divine attribute; to look for it in princes is a category error about where salvation comes from. Isaiah 31:1–3 makes the same argument against relying on Egypt.</p>',
    "4": '<p>"When his breath departs, he returns to the earth; on that very day his plans come to nothing" — <em>tēṣēʾ rûḥô yāšub lĕʾadmātô bayyôm hahûʾ ʾābĕdû ʿeštonōtāyw</em>. The mortality argument against patronage: the prince\'s breath (<em>rûaḥ</em>) departs (an echo of Gen 2:7; the same breath that constituted the living creature returns to God, Eccl 12:7; Ps 104:29). "On that very day (<em>bayyôm hahûʾ</em>) his plans come to nothing" — the plans (<em>ʿeštonōt</em>, from <em>šānat</em>, to deliberate, plan) of the most powerful patrons vaporize at the moment of death. The urgency of the warning: those who rely on mortal patrons are relying on someone whose plans will perish on a specific future day.</p>',
    "5": '<p>"Blessed is the one whose help is the God of Jacob, whose hope is in the LORD his God" — the beatitude that contrasts with the anti-patronage warning: the one whose patron is YHWH (specifically "the God of Jacob," the covenant God of the specific family who became Israel) is "blessed (<em>ʾašrê</em>)." The beatitude formula invites the hearer to recognize what constitutes genuine flourishing: not the client of the powerful prince but the client of YHWH. "God of Jacob (<em>ʾĕlōhê yaʿăqōb</em>)" — the patriarchal title emphasizing covenant continuity: the same God who chose Jacob and wrestled with him at Peniel (Gen 32:24–30) is the patron of the present worshipper.</p>',
    "6": '<p>"who made heaven and earth, the sea and everything in them, and who keeps faith forever" — <em>ʿōśēh šāmayim wāʾāreṣ ʾet-hayyām wĕʾet-kol-ʾăšer-bām</em>. The Creator\'s credentials as a reliable patron: YHWH made heaven and earth, sea and all that fills them — the comprehensive four-part inventory of creation (Exod 20:11; Neh 9:6; Ps 115:15; 124:8). The one who created everything is the most powerful patron imaginable — and "keeps faith forever (<em>šōmēr ʾĕmet lĕʿôlām</em>)": covenant faithfulness (<em>ʾĕmet</em>) maintained not for a human lifetime but eternally. The contrast with the prince whose plans perish on the day of his death is the point.</p>',
    "7": '<p>"who secures justice for the oppressed and gives food to the hungry. The LORD sets prisoners free" — the divine action catalogue of vv. 7–9 is one of the most concentrated lists of YHWH\'s covenant actions in the OT. It covers: justice for the oppressed (<em>ʿōśēh mišpāṭ laʿăšûqîm</em>), food for the hungry (<em>nōtēn leḥem lāreʿēbîm</em>), freedom for prisoners (<em>YHWH mattîr ʾăsûrîm</em>). Each divine act inverts a human situation of powerlessness. The sequence is closely paralleled in Isaiah 61:1–3 (the servant\'s mission: "to proclaim freedom for the captives... to release the oppressed") and in Jesus\'s answer to John the Baptist (Matt 11:4–5; Luke 7:22: "the blind receive sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, and the good news is proclaimed to the poor").</p>',
    "8": '<p>"the LORD gives sight to the blind, the LORD lifts up those who are bowed down, the LORD loves the righteous" — the divine action catalogue continues: sight for the blind (<em>YHWH pōqēaḥ ʿiwwĕrîm</em>), lifting the bowed (<em>YHWH zôqēp kĕpûpîm</em>), love for the righteous (<em>YHWH ʾōhēb ṣaddîqîm</em>). "Sight for the blind" was not ordinarily achieved through medical means in the ancient world — it was a divine act (Exod 4:11; John 9:39–41). Jesus\'s healing of the blind is therefore a direct enactment of YHWH\'s Ps 146:8 claim — the sign of the messianic era\'s arrival (Matt 9:27–31; 11:5; John 9). "Bowed down (<em>kĕpûpîm</em>)" — the same word as Ps 145:14, describing those bent under the weight of affliction.</p>',
    "9": '<p>"The LORD watches over the alien resident; he supports the fatherless and the widow; but the way of the wicked he overturns" — the three-fold vulnerable group formula: the <em>gēr</em> (alien resident, foreigner living within Israel without full citizenship rights), the <em>yātôm</em> (fatherless, orphan), and the <em>ʾalmānāh</em> (widow). This triad is one of the most repeated social-justice formulae of the Torah and prophets (Exod 22:21–22; Deut 10:18; 14:29; 24:17–21; 27:19; Jer 7:6; 22:3; Zech 7:10; Mal 3:5). YHWH\'s particular care for these three unprotected groups is the covenant\'s most concrete social obligation, and its violation is singled out for the most severe prophetic condemnation.</p>',
    "10": '<p>"The LORD will reign forever — your God, O Zion, for all generations. Praise the LORD!" — <em>yimlōk YHWH lĕʿôlām ʾĕlōhayik ṣiyyôn lĕdōr wādōr hallĕlû-Yāh</em>. The only occurrence in the Psalter of this precise eschatological form: <em>yimlōk YHWH</em> (YHWH will reign/shall reign, future tense), as distinguished from the enthronement psalms\' <em>YHWH malak</em> (YHWH has become king, or YHWH reigns, perfect/present). The future-looking assertion closes the psalm and opens the door to the remaining Hallel psalms: the eternal reign of YHWH is both present reality and forward promise. "Your God, O Zion (<em>ʾĕlōhayik ṣiyyôn</em>)" — Zion as the community of the covenant people, not merely the geographic city. The final "Praise the LORD (<em>hallĕlû-Yāh</em>)!" begins the chain of praise that continues through Psalm 150.</p>',
  },
}

# INTENT: mkt-context for Psalms 140–146 — five Davidic lament psalms (140–143), a royal
#   praise psalm that echoes Ps 18 (144), the acrostic Tĕhillāh whose title names the Psalter
#   (145), and the first of the Hallel finale (146) whose divine-action catalogue is quoted
#   by Jesus as evidence of the messianic era (Matt 11:4-5 / Luke 7:22).
# CHANGE? If mkt-context/psalms.json structure changes, update load_comm/save_comm source string.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/psalms.json'));
#   print('146 v7:', d.get('146',{}).get('7','MISSING')[:80])"

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Psalms mkt-context: {len(existing)} chapters, {total} verse entries total')
    print('Psalms 140–146 mkt-context written.')

if __name__ == '__main__':
    main()
